ALGORITHM MPI_Derived_Datatype_Usage
INPUT: None
OUTPUT: Derived datatype used for communication

BEGIN
 // Step 1: Construct the derived datatype
 CALL MPI_Type_contiguous(count, oldtype, newtype)
 // OR
 CALL MPI_Type_vector(count, blocklength, stride, oldtype, newtype)
 // OR
 CALL MPI_Type_indexed(count, blocklengths[], displacements[], oldtype, newtype)
 // OR
 CALL MPI_Type_create_struct(count, blocklengths[], displacements[], types[], newtype)

 // Step 2: Commit the derived datatype
 CALL MPI_Type_commit(newtype)

 // Step 3: Use the derived datatype in communication
 // For point-to-point
 CALL MPI_Send(buffer, 1, newtype, dest, tag, comm)
 // OR for collective
 CALL MPI_Bcast(buffer, 1, newtype, root, comm)

 // Step 4: Free the derived datatype when done
 CALL MPI_Type_free(newtype)

 RETURN
END

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>

/*
 * MPI Derived Datatype Example: MPI_Type_indexed
 * This demonstrates sending specific arbitrary elements from an array
 * using MPI_Type_indexed which allows irregular displacements and
 * variable block lengths.
 */

#define BUFFER_SIZE 20

int main(int argc, char *argv[]) {
 int rank, nprocs;
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &nprocs);

 if (nprocs < 2) {
 printf("This example requires at least 2 processes\n");
 MPI_Finalize();
 return 1;
 }

 int array[BUFFER_SIZE];

 // Initialize array: 0, 1, 2, 3, ..., 19
 for (int i = 0; i < BUFFER_SIZE; i++) {
 array[i] = i;
 }

 if (rank == 0) {
 printf("Original array: ");
 for (int i = 0; i < BUFFER_SIZE; i++) {
 printf("%d ", array[i]);
 }
 printf("\n");

 // Define the indexed datatype to send elements at positions:
 // - 1 element at index 2
 // - 2 elements starting at index 5
 // - 3 elements starting at index 10

 int count = 3; // Number of blocks
 int blocklengths[3] = {1, 2, 3}; // Length of each block
 int displacements[3]; // Byte displacements for each block

 // Calculate byte displacements from start of array
 displacements[0] = 2 * sizeof(int); // Index 2
 displacements[1] = 5 * sizeof(int); // Index 5
 displacements[2] = 10 * sizeof(int); // Index 10

 // Create the indexed datatype
 MPI_Datatype indexed_type;
 MPI_Type_indexed(count, blocklengths, displacements, MPI_INT, &indexed_type);
 MPI_Type_commit(&indexed_type);

 // Send using the indexed datatype (count = 1 means 1 instance of the type)
 MPI_Send(array, 1, indexed_type, 1, 100, MPI_COMM_WORLD);

 MPI_Type_free(&indexed_type);

 printf("Process 0: Sent elements at indices [2], [5-6], [10-12]\n");

 } else if (rank == 1) {
 // Receive the same pattern
 int received[6]; // Total elements: 1 + 2 + 3 = 6

 // Create the same indexed datatype on receiver side
 int count = 3;
 int blocklengths[3] = {1, 2, 3};
 int displacements[3];
 displacements[0] = 0; // Starting at beginning of receive buffer
 displacements[1] = 1 * sizeof(int);
 displacements[2] = 3 * sizeof(int);

 MPI_Datatype indexed_type;
 MPI_Type_indexed(count, blocklengths, displacements, MPI_INT, &indexed_type);
 MPI_Type_commit(&indexed_type);

 MPI_Recv(received, 1, indexed_type, 0, 100, MPI_COMM_WORLD, MPI_STATUS_IGNORE);

 MPI_Type_free(&indexed_type);

 printf("Process 1 received: ");
 for (int i = 0; i < 6; i++) {
 printf("%d ", received[i]);
 }
 printf("\n");
 }

 MPI_Finalize();
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <mpi.h>

/*
 * MPI Derived Datatype Example: MPI_Type_create_struct
 * This demonstrates creating a derived datatype for a C struct
 * containing multiple fields of different types.
 */

typedef struct {
 int id;
 double position[3];
 double velocity[3];
 char type;
} Particle;

int main(int argc, char *argv[]) {
 int rank, nprocs;
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &nprocs);

 if (nprocs < 2) {
 printf("This example requires at least 2 processes\n");
 MPI_Finalize();
 return 1;
 }

 // Define the structure datatype
 #define NUM_FIELDS 4
 int blocklengths[NUM_FIELDS] = {1, 3, 3, 1};
 MPI_Aint displacements[NUM_FIELDS];
 MPI_Datatype types[NUM_FIELDS] = {MPI_INT, MPI_DOUBLE, MPI_DOUBLE, MPI_CHAR};

 // Create a temporary particle to get proper displacements
 Particle temp_particle;
 MPI_Aint base_address;
 MPI_Get_address(&temp_particle, &base_address);

 // Get addresses of each field and compute displacements
 MPI_Get_address(&temp_particle.id, &displacements[0]);
 MPI_Get_address(&temp_particle.position, &displacements[1]);
 MPI_Get_address(&temp_particle.velocity, &displacements[2]);
 MPI_Get_address(&temp_particle.type, &displacements[3]);

 // Calculate relative displacements from base
 for (int i = 0; i < NUM_FIELDS; i++) {
 displacements[i] = MPI_Aint_diff(displacements[i], base_address);
 }

 // Create and commit the struct datatype
 MPI_Datatype particle_type;
 MPI_Type_create_struct(NUM_FIELDS, blocklengths, displacements, types, &particle_type);
 MPI_Type_commit(&particle_type);

 if (rank == 0) {
 // Create and populate a particle
 Particle p;
 p.id = 42;
 p.position[0] = 1.5; p.position[1] = 2.5; p.position[2] = 3.5;
 p.velocity[0] = 0.1; p.velocity[1] = 0.2; p.velocity[2] = 0.3;
 p.type = 'A';

 printf("Process 0 sending Particle:\n");
 printf(" ID: %d\n", p.id);
 printf(" Position: (%.2f, %.2f, %.2f)\n", 
 p.position[0], p.position[1], p.position[2]);
 printf(" Velocity: (%.2f, %.2f, %.2f)\n", 
 p.velocity[0], p.velocity[1], p.velocity[2]);
 printf(" Type: %c\n", p.type);

 // Send the particle using the struct datatype
 MPI_Send(&p, 1, particle_type, 1, 200, MPI_COMM_WORLD);

 } else if (rank == 1) {
 Particle received;

 // Receive the particle
 MPI_Recv(&received, 1, particle_type, 0, 200, MPI_COMM_WORLD, MPI_STATUS_IGNORE);

 printf("Process 1 received Particle:\n");
 printf(" ID: %d\n", received.id);
 printf(" Position: (%.2f, %.2f, %.2f)\n", 
 received.position[0], received.position[1], received.position[2]);
 printf(" Velocity: (%.2f, %.2f, %.2f)\n", 
 received.velocity[0], received.velocity[1], received.velocity[2]);
 printf(" Type: %c\n", received.type);
 }

 // Free the datatype
 MPI_Type_free(&particle_type);

 MPI_Finalize();
 return 0;
}
